<template>
  <div id="app">
    <div class="header">
      <ul class="header-button-left" v-on:click="cancel">
        <li>Cancel</li>
      </ul>
      <ul class="header-button-right" v-if="step == 2" v-on:click="next">
        <li>Next</li>
      </ul>
      <ul class="header-button-right" v-if="step == 3" v-on:click="publish" >
        <li>Send</li>
      </ul>
      
      <img src="./assets/logo.png" class="logo">
    </div>
    
    <!--
    <p>{{$store.getters.getName}}</p>
    <button v-on:click="$store.commit('setName', '이순신')">이름변경하기_commit</button>
    <button v-on:click="$store.dispatch('setName', '홍길동')">이름변경하기_dispatch</button>
    -->
    <Body 
      v-bind:포스팅들="포스팅들" 
      v-bind:step="step"
      v-bind:uploadImg="uploadImg"
      v-bind:선택한필터="선택한필터"
      v-on:hyodo="data_caption = $event"
    />

    <button v-on:click="more">더보기</button>

    <div class="footer">
      <ul class="footer-button-plus">
        <li>
          <input type="file" id="file" class="inputfile" v-on:change="uploadImage" >
          <label for="file" class="input-plus">+</label>
        </li>
      </ul>
    </div>

  <!--
    
  -->
  </div>
</template>

<script>
import Body from './components/Body.vue';
import postData from './data/postdata.js';
import EventBus from './EventBus.js';
import axios from 'axios';

export default {
  name: 'app',
  components: {
    Body
  },
  data() {
    return {
      포스팅들 : postData,
      step : 1,
      uploadImg : '',
      data_caption : '',
      선택한필터 : ''
    } 
  },
  methods: {
    cancel() {
      this.step = 1;
    },
    next() {
      this.step++;
    },
    uploadImage(e) {
      let file = e.target.files;
      let reader = new FileReader();
      reader.readAsDataURL(file[0]);
      reader.onload = e => {
        //console.log(e.target.result) 
        this.step = 2;
        this.uploadImg = e.target.result;
      }
    },
    publish() {
      //1. 메인화면으로 돌아감
      this.step = 1;
      //2. 이미지&글 포스팅 추가
      let 내데이터 = {
        postImage : this.uploadImg,
        caption : this.data_caption,
        date : 'May 5'
      }
      this.포스팅들.unshift(내데이터);
    },
    more() {
      axios.get('/more.json')
        .then(결과 => {
            this.포스팅들.push(결과);
      })
    }
  },
  mounted() {
    EventBus.$on('select-filter', (받은자료) => {
      this.선택한필터 = 받은자료;
    });
  }
}
</script>

