<template>
    <div v-bind:class="['filter-item', 필터]" 
        v-bind:style="{ backgroundImage: `url( ${uploadImg} )` }"
        v-on:click="clickBox">
    
        <slot></slot>
    </div>
</template>

<script>
import EventBus from './../EventBus.js';

export default {
    name: 'FilterBox',
    data() {
        return {
            
        }
    },
    props : {
        uploadImg : String,
        필터 : String
    },
    methods : {
        clickBox() {
            EventBus.$emit('select-filter', this.필터)
        }
    }
}
</script>

<style>
.filter-item {
    width: 100px;
    height: 100px;
    margin: 10px 10px 10px auto;
    padding: 8px;
    display: inline-block;
    color : white;
    background-size: cover;
    background-color: #000;
    background-position: center;
}
</style>
