import Vue from 'vue'
import Vuex from 'vuex'
//import axios from 'axios';

Vue.use(Vuex);

export let store = new Vuex.Store({
  state : {
      name : '홍길동',
      age : 100,
      likes : 36,
      likes_state : false
  },
  getters : {
      getName(state) {
        return state.name;
      },
      getLikes(state) {
        return state.likes;
      }
  },
  mutations: {
      setName(state, 이름) {
        state.name = 이름;
      },
      addLikes(state) {
        if (state.likes_state) {
            state.likes--;
            state.likes_state = false;
        } else {
            state.likes++;
            state.likes_state = true;
        }
      }
  },
  actions : {
      setName(context, 데이터) {
          //ajax 요청을 통한 데이터 비동기 통신이 가능
          context.commit("setName", 데이터);
      },
      addLikes(context) {
        //ajax 요청을 통한 데이터 비동기 통신이 가능
        context.commit("addLikes");
    }
  }  
})
